import React, { useEffect, useState } from "react";
import axios from "axios";
import { toast } from "react-hot-toast";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const [notes, setNotes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [newNote, setNewNote] = useState({ title: "", content: "" });
  const navigate = useNavigate();

  // Fetch Notes
  useEffect(() => {
    const fetchNotes = async () => {
      try {
        setLoading(true);
        const response = await axios.get("http://localhost:4000/api/note/getnotes", {
          withCredentials: true,
          headers: { "Content-Type": "application/json" },
        });
        setNotes(response.data.notes || []);
        setError(null);
      } catch (error) {
        console.error(error);
        setError("Failed to fetch notes");
      } finally {
        setLoading(false);
      }
    };
    fetchNotes();
  }, []);

  // Create Note
  const createNote = async () => {
    if (!newNote.title || !newNote.content) {
      toast.error("Please enter both title and content");
      return;
    }
    try {
      const response = await axios.post(
        "http://localhost:4000/api/note/createnote",
        newNote,
        {
          withCredentials: true,
          headers: { "Content-Type": "application/json" },
        }
      );
      toast.success(response.data.message);
      setNotes([...notes, response.data.newNote]);
      setNewNote({ title: "", content: "" });
      setError(null);
    } catch (error) {
      console.error(error);
      setError("Failed to create note");
    }
  };

  // Update Note
  const updateNote = async (id, updatedFields) => {
    try {
      const response = await axios.put(
        `http://localhost:4000/api/note/updatenote/${id}`,
        updatedFields,
        {
          withCredentials: true,
          headers: { "Content-Type": "application/json" },
        }
      );
      toast.success(response.data.message);
      setNotes(notes.map((n) => (n._id === id ? response.data.updatedNote : n)));
    } catch (error) {
      console.error(error);
      setError("Failed to update note");
    }
  };

  // Delete Note
  const deleteNote = async (id) => {
    try {
      const response = await axios.delete(
        `http://localhost:4000/api/note/deletenote/${id}`,
        {
          withCredentials: true,
          headers: { "Content-Type": "application/json" },
        }
      );
      toast.success(response.data.message);
      setNotes(notes.filter((n) => n._id !== id));
    } catch (error) {
      console.error(error);
      setError("Failed to delete note");
    }
  };

  // Logout
  const logout = async () => {
    try {
      const response = await axios.get("http://localhost:4000/api/user/logout", {
        withCredentials: true,
      });
      toast.success(response.data.message);
      localStorage.removeItem("jwt");
      navigate("/login");
    } catch (error) {
      console.error(error);
      setError("Failed to logout");
    }
  };

  return (

    <div className="max-w-lg m-auto mx-auto p-6 rounded-lg shadow-lg bg-white">
      <h1 className="text-2xl font-semibold text-center text-gray-700 mb-4">
        📝 Notes App
      </h1>

      {/* Input fields */}
      <div className="space-y-3 mb-6">
        <input
          type="text"
          placeholder="Note Title"
          className="w-full p-2 border rounded bg-gray-100 focus:outline-none"
          value={newNote.title}
          onChange={(e) => setNewNote({ ...newNote, title: e.target.value })}
        />
        <textarea
          placeholder="Write your note..."
          className="w-full p-2 border rounded bg-gray-100 focus:outline-none"
          rows="3"
          value={newNote.content}
          onChange={(e) => setNewNote({ ...newNote, content: e.target.value })}
        />
        <button
          onClick={createNote}
          className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-800 transition-all w-full"
        >
          Add Note
        </button>
      </div>

      {/* Notes List */}
      {loading ? (
        <p className="text-center text-gray-500">Loading notes...</p>
      ) : error ? (
        <p className="text-center text-red-600">{error}</p>
      ) : notes.length === 0 ? (
        <p className="text-center text-gray-500">No notes found.</p>
      ) : (
        <ul className="space-y-3">
          {notes.map((note) => (
            <li
              key={note._id}
              className="p-4 border rounded-lg shadow-sm bg-gray-50 hover:bg-gray-100 transition-all"
            >
              <div className="flex justify-between items-center">
                <h3 className="text-lg font-semibold">{note.title}</h3>
                <div className="flex gap-2">
                  <button
                    onClick={() =>
                      updateNote(note._id, {
                        title: prompt("Edit title:", note.title) || note.title,
                        content:
                          prompt("Edit content:", note.content) || note.content,
                      })
                    }
                    className="text-blue-500 hover:text-blue-700"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => deleteNote(note._id)}
                    className="text-red-600 hover:text-red-800"
                  >
                    Delete
                  </button>
                </div>
              </div>
              <p className="mt-2 text-gray-700">{note.content}</p>
            </li>
          ))}
        </ul>
      )}

      {/* Logout */}
      <button
        onClick={logout}
        className="mt-6 bg-red-500 text-white px-4 py-2 rounded hover:bg-red-700 w-full transition-all"
      >
        Logout
      </button>
    </div>
  );
};

export default Home;
